<?php
namespace App\Http\Controllers\Tenant;use App\Http\Controllers\Controller;use App\Models\ReportExport;use App\Services\ExportService;use Illuminate\Http\Request;use Illuminate\Support\Facades\Storage;
class ReportExportController extends Controller{use Concerns;public function store(Request $r,ExportService $s){$this->requirePerm('tenant.reports.export');$d=$r->validate(['report_key'=>'required|string','format'=>'required|in:pdf,xlsx,csv','filters'=>'array']);$e=$s->requestExport($d['report_key'],$d['filters']??[],$d['format'],$r->user());return redirect('/reports/exports')->with('status','Export queued #'.$e->id);}public function index(){return view('tenant.reports.exports',['exports'=>ReportExport::latest()->paginate(30)]);}public function download(ReportExport $export){$this->requirePerm('tenant.reports.export');abort_unless($export->workspace_id===app(\App\Support\CurrentWorkspace::class)->required()->id,404);abort_unless($export->status==='completed'&&$export->file_path,404);return Storage::disk($export->file_disk)->download($export->file_path,basename($export->file_path));}}
